// cursor_workflow_engine.cpp
#include "cursor_workflow_engine.h"

void CursorWorkflowEngine::triggerInlineCompletion(const CursorContext& ctx) {
    // Build context-rich prompt like Cursor
    std::string prompt = buildCursorPrompt(ctx);
    
    // Route to appropriate model based on context complexity
    auto router = m_hub->getModelRouter();
    std::string model = router->selectModelForTask({
        .taskType = TaskType::INLINE_COMPLETION,
        .complexity = calculateComplexity(ctx),
        .latencyRequirement = 50ms,  // Sub-50ms for inline
        .contextWindow = estimateContext(ctx)
    });
    
    // Stream completion with aggressive caching
    m_hub->getCompletionEngine()->streamCompletion({
        .prompt = prompt,
        .model = model,
        .maxTokens = 150,  // Cursor-style short completions
        .temperature = 0.2,  // Low temp for deterministic completions
        .stopSequences = {"\n", ";", "}"},
        .onToken = [this](const std::string& token) {
            m_currentCompletion += token;
            emit partialCompletion(token);  // Real-time UI updates
        }
    });
}

std::string CursorWorkflowEngine::buildCursorPrompt(const CursorContext& ctx) {
    std::ostringstream prompt;
    
    // Cursor-style context building
    prompt << "Complete the code at cursor position. Consider:\n";
    prompt << "- Current file: " << ctx.currentFile << "\n";
    prompt << "- Cursor at line " << ctx.cursorLine << ", column " << ctx.cursorColumn << "\n";
    prompt << "- Recent edits: " << join(ctx.recentEdits, ", ") << "\n";
    prompt << "- Language: " << detectLanguage(ctx.currentFile) << "\n";
    
    // Add surrounding context (like Cursor's 100-line window)
    auto surroundingCode = getSurroundingCode(ctx.currentFile, ctx.cursorLine, 50);
    prompt << "- Surrounding code:\n```\n" << surroundingCode << "\n```\n";
    
    // Add imports/dependencies context
    auto imports = getFileImports(ctx.currentFile);
    if (!imports.empty()) {
        prompt << "- Imports: " << join(imports, ", ") << "\n";
    }
    
    // Add project-wide patterns
    auto patterns = m_hub->getContextAnalyzer()->getProjectPatterns();
    prompt << "- Common patterns in project: " << patterns << "\n";
    
    prompt << "\nComplete this code naturally and idiomatically:\n";
    prompt << getLineAtCursor(ctx.currentFile, ctx.cursorLine);
    
    return prompt.str();
}
