// github_copilot_integration.cpp
#include "github_copilot_integration.h"

void GitHubCopilotIntegration::reviewPullRequest(const CopilotContext& ctx) {
    // Get the diff
    std::string diff = getPullRequestDiff(ctx.pullRequest);
    
    // Build comprehensive review context
    std::string prompt = buildPRReviewPrompt(diff, ctx);
    
    // Use advanced coding agent for review
    m_executor->executeUserRequest({
        .task = "review_pull_request",
        .input = prompt,
        .context = {
            {"repository", ctx.repository},
            {"branch", ctx.branch},
            {"changed_files", join(ctx.changedFiles, ",")}
        },
        .onProgress = [this](const std::string& step, double progress) {
            emit reviewProgress(step, progress);
        }
    });
}

std::string GitHubCopilotIntegration::buildPRReviewPrompt(
    const std::string& diff, const CopilotContext& ctx) {
    
    std::ostringstream prompt;
    prompt << "You are an expert code reviewer. Review this pull request thoroughly:\n\n";
    
    prompt << "Repository: " << ctx.repository << "\n";
    prompt << "Branch: " << ctx.branch << "\n";
    prompt << "Changed files: " << join(ctx.changedFiles, ", ") << "\n";
    
    if (!ctx.issueDescription.empty()) {
        prompt << "Related issue: " << ctx.issueDescription << "\n";
    }
    
    prompt << "\n=== DIFF ===\n" << diff << "\n=== END DIFF ===\n\n";
    
    prompt << "Review criteria:\n";
    prompt << "1. Code quality and readability\n";
    prompt << "2. Potential bugs or logic errors\n";
    prompt << "3. Performance implications\n";
    prompt << "4. Security vulnerabilities\n";
    prompt << "5. Test coverage\n";
    prompt << "6. Documentation completeness\n";
    prompt << "7. Adherence to project conventions\n\n";
    
    prompt << "Provide specific, actionable feedback with line numbers. ";
    prompt << "Suggest improvements and explain reasoning.\n";
    
    return prompt.str();
}
