class AIChatPanelWiring : public QObject {
    Q_OBJECT

public:
    AIChatPanelWiring(AIChatPanel* panel, AgenticEngine* engine, MainWindow* mainWindow);
    void initializeWiring();

private slots:
    void onMessageSubmitted(const QString& message);
    void onModelReady(bool ready);
    void onResponseReady(const QString& response, bool complete);
    void onTokenGenerated(const QString& token);
    void onModelSelected(const QString& modelName);
    void onQuickActionTriggered(const QString& action);

private:
    void injectEditorContext();
    QString gatherEditorContext();
    QString getSelectedText();
    QString getSurroundingCode();
    void updateModelStatus();
    void enableInput(bool enable);
    
    AIChatPanel* m_panel;
    AgenticEngine* m_engine;
    MainWindow* m_mainWindow;
    
    bool m_modelReady;
    QString m_currentModel;
    QString m_accumulatingResponse;
};

// ai_chat_panel_wiring.cpp
#include "ai_chat_panel_wiring.h"

AIChatPanelWiring::AIChatPanelWiring(AIChatPanel* panel, AgenticEngine* engine, MainWindow* mainWindow)
    : m_panel(panel), m_engine(engine), m_mainWindow(mainWindow), m_modelReady(false) {
    
    initializeWiring();
}

void AIChatPanelWiring::initializeWiring() {
    // Core inference connections
    connect(m_panel, &AIChatPanel::messageSubmitted, this, &AIChatPanelWiring::onMessageSubmitted);
    connect(m_engine, &AgenticEngine::responseReady, this, &AIChatPanelWiring::onResponseReady);
    connect(m_engine, &AgenticEngine::tokenGenerated, this, &AIChatPanelWiring::onTokenGenerated);
    connect(m_engine, &AgenticEngine::modelReady, this, &AIChatPanelWiring::onModelReady);
    
    // Model selection
    connect(m_mainWindow, &MainWindow::modelSelected, this, &AIChatPanelWiring::onModelSelected);
    connect(m_panel, &AIChatPanel::quickActionTriggered, this, &AIChatPanelWiring::onQuickActionTriggered);
    
    // Initial state
    updateModelStatus();
}

void AIChatPanelWiring::onMessageSubmitted(const QString& message) {
    if (!m_modelReady) {
        m_panel->addSystemMessage("⚠️ No model loaded. Please select a GGUF model first.");
        return;
    }
    
    // Add user message
    m_panel->addUserMessage(message);
    
    // Gather editor context
    QString context = gatherEditorContext();
    
    // Start streaming response
    m_accumulatingResponse.clear();
    m_panel->startStreaming();
    
    // Process through agentic engine with context
    m_engine->processMessage(message, context);
}

void AIChatPanelWiring::onTokenGenerated(const QString& token) {
    m_accumulatingResponse += token;
    m_panel->updateStreamingMessage(m_accumulatingResponse);
}

void AIChatPanelWiring::onResponseReady(const QString& response, bool complete) {
    if (complete) {
        m_panel->finishStreaming();
        m_accumulatingResponse.clear();
    }
}

void AIChatPanelWiring::onModelReady(bool ready) {
    m_modelReady = ready;
    updateModelStatus();
    enableInput(ready);
}

QString AIChatPanelWiring::gatherEditorContext() {
    QString context;
    
    // Get current file
    QString currentFile = m_mainWindow->getCurrentFile();
    if (!currentFile.isEmpty()) {
        context += QString("Current file: %1\n").arg(currentFile);
    }
    
    // Get selected text
    QString selectedText = getSelectedText();
    if (!selectedText.isEmpty()) {
        context += QString("Selected text:\n```\n%1\n```\n").arg(selectedText);
    }
    
    // Get surrounding code (±20 lines)
    QString surroundingCode = getSurroundingCode();
    if (!surroundingCode.isEmpty()) {
        context += QString("Surrounding code:\n```\n%1\n```\n").arg(surroundingCode);
    }
    
    // Get recent edits
    QStringList recentEdits = m_mainWindow->getRecentEdits();
    if (!recentEdits.isEmpty()) {
        context += QString("Recent changes: %1\n").arg(recentEdits.join(", "));
    }
    
    // Get project context
    QString projectType = detectProjectType(currentFile);
    if (!projectType.isEmpty()) {
        context += QString("Project type: %1\n").arg(projectType);
    }
    
    return context;
}

QString AIChatPanelWiring::getSelectedText() {
    QTextCursor cursor = m_mainWindow->getActiveEditor()->textCursor();
    if (cursor.hasSelection()) {
        return cursor.selectedText();
    }
    return QString();
}

QString AIChatPanelWiring::getSurroundingCode() {
    QTextEdit* editor = m_mainWindow->getActiveEditor();
    if (!editor) return QString();
    
    QTextCursor cursor = editor->textCursor();
    int currentLine = cursor.blockNumber();
    
    // Get ±20 lines around cursor
    QString allText = editor->toPlainText();
    QStringList lines = allText.split('\n');
    
    int startLine = std::max(0, currentLine - 20);
    int endLine = std::min(lines.size() - 1, currentLine + 20);
    
    QStringList surroundingLines;
    for (int i = startLine; i <= endLine; ++i) {
        surroundingLines.append(lines[i]);
    }
    
    return surroundingLines.join('\n');
}

void AIChatPanelWiring::updateModelStatus() {
    if (m_modelReady && !m_currentModel.isEmpty()) {
        m_panel->setStatusText(QString("Model: %1").arg(m_currentModel));
        m_panel->setStatusIcon(":/icons/model-loaded.png");
    } else {
        m_panel->setStatusText("No model loaded");
        m_panel->setStatusIcon(":/icons/model-unloaded.png");
    }
}

void AIChatPanelWiring::enableInput(bool enable) {
    m_panel->setInputEnabled(enable);
    if (!enable) {
        m_panel->setPlaceholderText("Loading model...");
    } else {
        m_panel->setPlaceholderText("Ask a question or describe what you want to build...");
    }
}
