    updateUIState();
    
    // Find the actual GGUF file
    QString modelPath = findModelFile(modelName);
    if (modelPath.isEmpty()) {
        emit error("Model file not found: " + modelName);
        m_loading = false;
        m_selector->setLoading(false);
        return;
    }
    
    loadModel(modelPath);
}

QString ModelLifecycleManager::findModelFile(const QString& modelName) {
    // Search common GGUF locations
    QStringList searchPaths = {
        QDir::home().filePath("models"),
        QDir::current().filePath("models"),
        QStandardPaths::writableLocation(QStandardPaths::AppDataLocation) + "/models"
    };
    
    for (const QString& path : searchPaths) {
        QDir dir(path);
        QStringList filters;
        filters << modelName + "*.gguf" << "*"+modelName+"*.gguf";
        
        QStringList files = dir.entryList(filters, QDir::Files);
        if (!files.isEmpty()) {
            return dir.filePath(files.first());
        }
    }
    
    return QString();
}
