// streaming_ui_manager.cpp
#include "streaming_ui_manager.h"

StreamingUIManager::StreamingUIManager(AIChatPanel* panel)
    : m_panel(panel), m_lastUpdateLength(0), m_isStreaming(false) {
    
    m_typingTimer = new QTimer(this);
    m_typingTimer->setInterval(50);  // Smooth typing effect
    connect(m_typingTimer, &QTimer::timeout, this, &StreamingUIManager::onTypingUpdate);
    
    m_timeoutTimer = new QTimer(this);
    m_timeoutTimer->setInterval(30000);  // 30 second timeout
    m_timeoutTimer->setSingleShot(true);
    connect(m_timeoutTimer, &QTimer::timeout, this, &StreamingUIManager::onStreamingTimeout);
}

void StreamingUIManager::startStreaming() {
    m_isStreaming = true;
    m_streamingContent.clear();
    m_lastUpdateLength = 0;
    
    showTypingIndicator();
    m_typingTimer->start();
    m_timeoutTimer->start();
    
    emit streamingStarted();
}

void StreamingUIManager::updateStreamingMessage(const QString& content) {
    m_streamingContent = content;
    
    // Animate the content update for smooth UX
    animateContent(content);
}

void StreamingUIManager::animateContent(const QString& newContent) {
    // Smooth character-by-character reveal
    int targetLength = newContent.length();
    
    if (targetLength > m_lastUpdateLength) {
        // Add new characters gradually
        QString visibleContent = newContent.left(m_lastUpdateLength + 1);
        m_panel->updateStreamingMessage(visibleContent);
        m_lastUpdateLength++;
    } else {
        // Update immediately for corrections
        m_panel->updateStreamingMessage(newContent);
        m_lastUpdateLength = targetLength;
    }
}

void StreamingUIManager::finishStreaming() {
    if (!m_isStreaming) return;
    
    m_isStreaming = false;
    m_typingTimer->stop();
    m_timeoutTimer->stop();
    
    hideTypingIndicator();
    m_panel->finishStreaming();
    
    emit streamingFinished();
}
