COPILOT_MODEL_GPT35 DB "gpt-3.5-turbo",0

.CODE

CopilotProtocol_BuildChatRequest PROC \
        pMessages:QWORD, \
        messageCount:DWORD, \
        pModel:QWORD, \
        maxTokens:DWORD
    
    LOCAL hHeap:QWORD
    LOCAL pJson:QWORD
    LOCAL cbJson:DWORD
    
    invoke GetProcessHeap
    mov hHeap, rax
    mov rcx, rax
    mov rdx, HEAP_ZERO_MEMORY
    mov r8d, 65536            ; 64 KB for JSON
    call HeapAlloc
    mov pJson, rax
    
    ; Build JSON request body
    lea rcx, pJson
    lea rdx, `{"model":"%s","messages":[`,0
    invoke wsprintfA, rcx, rdx, pModel
    
    ; Loop through messages and add to JSON
    mov ecx, messageCount
    mov rsi, pMessages
    .repeat
        mov rax, [rsi]        ; pMessage
        mov rdx, [rsi+8]      ; pRole
        ; Append: {"role":"...","content":"..."}
        ; [Full JSON construction - 150 lines]
        add rsi, 16
    .untilcxz
    
    lea rcx, pJson
    lea rdx, `],"max_tokens":%d}`,0
    invoke wsprintfA, rcx, rdx, maxTokens
    
    mov rax, pJson
    ret
CopilotProtocol_BuildChatRequest ENDP

CopilotProtocol_ParseResponse PROC pResponse:QWORD
    LOCAL pContent:QWORD
    
    ; Parse streaming response line: data: {"choices":[{"delta":{"content":"..."}}]}
    invoke JsonExtractString, pResponse, "content", 0
    mov pContent, rax
    
    ; Handle [DONE] marker
    invoke lstrcmpA, pContent, "[DONE]"
    .if eax == 0
        xor rax, rax
        ret
    .endif
    
    mov rax, pContent
    ret
CopilotProtocol_ParseResponse ENDP

