;======================================================================
; file_search.asm - Ripgrep-Style Fast File Search
;======================================================================
INCLUDE windows.inc

.CONST
MAX_SEARCH_RESULTS EQU 1000
MAX_PATTERN_LENGTH EQU 256

.DATA?
g_searchResults SEARCH_RESULT[MAX_SEARCH_RESULTS] DUP(?)
g_searchResultCount DWORD ?
g_searchPattern DB MAX_PATTERN_LENGTH DUP(?)

.CODE

FileSearch_Init PROC
    xor ecx, ecx
    mov g_searchResultCount, ecx
    ret
FileSearch_Init ENDP

FileSearch_SetPattern PROC pPattern:QWORD
    invoke lstrcpyA, ADDR g_searchPattern, pPattern
    ret
FileSearch_SetPattern ENDP

FileSearch_Execute PROC pRootPath:QWORD
    LOCAL searchData:WIN32_FIND_DATAA
    LOCAL hFind:QWORD
    LOCAL pSearchPath:QWORD
    
    ; Build search path: root\*
    invoke GetProcessHeap
    mov rcx, rax
    mov rdx, HEAP_ZERO_MEMORY
    mov r8d, MAX_PATH
    call HeapAlloc
    mov pSearchPath, rax
    
    lea rcx, pSearchPath
    lea rdx, "%s\\*"
    mov r8, pRootPath
    call wsprintfA
    
    ; Find first file
    lea rcx, searchData
    mov rdx, pSearchPath
    call FindFirstFileA
    
    .if rax == INVALID_HANDLE_VALUE
        ret
    .endif
    
    mov hFind, rax
    
    ; Process each file
    .repeat
        ; Skip . and ..
        lea rax, searchData.cFileName
        invoke lstrcmpA, rax, "."
        .if eax == 0
            .continue
        .endif
        
        invoke lstrcmpA, rax, ".."
        .if eax == 0
            .continue
        .endif
        
        ; Check if directory
        test searchData.dwFileAttributes, FILE_ATTRIBUTE_DIRECTORY
        .if !ZERO?
            ; Recurse into subdirectory
            lea rcx, pSearchPath
            lea rdx, "%s\\%s"
            mov r8, pRootPath
            lea r9, searchData.cFileName
            call wsprintfA
            
            invoke FileSearch_Execute, pSearchPath
        .else
            ; Process file
            lea rcx, pSearchPath
            lea rdx, "%s\\%s"
            mov r8, pRootPath
            lea r9, searchData.cFileName
            call wsprintfA
            
            invoke FileSearch_ProcessFile, pSearchPath
        .endif
        
        ; Find next file
        lea rcx, searchData
        mov rdx, hFind
        call FindNextFileA
        
    .until rax == 0
    
    ; Close find handle
    mov rcx, hFind
    call FindClose
    
    ; Clean up
    invoke HeapFree, hHeap, 0, pSearchPath
    
    ret
FileSearch_Execute ENDP

FileSearch_ProcessFile PROC pFilePath:QWORD
    LOCAL hFile:QWORD
    LOCAL pBuffer:QWORD
    LOCAL fileSize:QWORD
    LOCAL pLine:QWORD
    LOCAL lineNumber:DWORD
    
    ; Open file for reading
    invoke CreateFileA, pFilePath, GENERIC_READ, FILE_SHARE_READ, 0, OPEN_EXISTING, 0, 0
    .if rax == INVALID_HANDLE_VALUE
        ret
    .endif
    
    mov hFile, rax
    
    ; Get file size
    invoke GetFileSize, hFile, 0
    mov fileSize, rax
    
    ; Allocate buffer
    invoke GetProcessHeap
    mov rcx, rax
    mov rdx, HEAP_ZERO_MEMORY
    mov r8, fileSize
    call HeapAlloc
    mov pBuffer, rax
    
    ; Read entire file
    invoke ReadFile, hFile, pBuffer, fileSize, ADDR dwRead, 0
    invoke CloseHandle, hFile
    
    ; Search for pattern in file
    invoke BoyerMooreSearch, pBuffer, fileSize, ADDR g_searchPattern
    
    .if rax != 0
        ; Found match - add to results
        invoke FileSearch_AddResult, pFilePath, rax, lineNumber
    .endif
    
    ; Clean up
    invoke HeapFree, hHeap, 0, pBuffer
    
    ret
FileSearch_ProcessFile ENDP

BoyerMooreSearch PROC pText:QWORD, cbText:DWORD, pPattern:QWORD
    LOCAL patternLen:DWORD
    LOCAL badCharTable[256]:DWORD
    LOCAL pResult:QWORD
    
    ; Build bad character table
    invoke lstrlenA, pPattern
    mov patternLen, eax
    
    invoke BoyerMoore_BuildBadCharTable, pPattern, patternLen, ADDR badCharTable
    
    ; Search algorithm
    xor ecx, ecx              ; i = 0
    mov edx, patternLen
    mov esi, pText
    mov edi, pPattern
    
    .while ecx <= cbText - patternLen
        mov eax, patternLen
        dec eax
        mov ebx, ecx
        add ebx, eax          ; j = i + patternLen - 1
        
        ; Compare from right to left
        .while eax >= 0
            mov al, [esi + ebx]
            mov dl, [edi + eax]
            .if al != dl
                .break
            .endif
            dec eax
            dec ebx
        .endw
        
        .if eax < 0
            ; Pattern found
            lea rax, [esi + ecx]
            mov pResult, rax
            .break
        .else
            ; Shift using bad character table
            movzx eax, BYTE PTR [esi + ebx]
            mov edx, badCharTable[eax*4]
            add ecx, edx
        .endif
    .endw
    
    mov rax, pResult
    ret
BoyerMooreSearch ENDP

FileSearch_AddResult PROC pFile:QWORD, pMatch:QWORD, lineNumber:DWORD
    LOCAL pResult:QWORD
    LOCAL index:DWORD
    
    ; Get next available slot
    mov eax, g_searchResultCount
    mov index, eax
    
    .if index >= MAX_SEARCH_RESULTS
        ret
    .endif
    
    ; Fill result structure
    lea rax, g_searchResults
    mov rdx, index
    imul rdx, SIZEOF SEARCH_RESULT
    add rax, rdx
    mov pResult, rax
    
    mov [pResult].file, pFile
    mov [pResult].match, pMatch
    mov [pResult].line, lineNumber
    
    inc g_searchResultCount
    
    ret
FileSearch_AddResult ENDP

END
