;======================================================================
; cursor_multi_cursor.asm - Multi-Cursor Editing Engine
;======================================================================
INCLUDE windows.inc

.CONST
MAX_CURSORS EQU 10

.DATA?
g_cursors CURSOR[MAX_CURSORS] DUP(?)
g_cursorCount DWORD ?
g_activeCursorIndex DWORD ?

.CODE

MultiCursor_Init PROC
    xor ecx, ecx
    mov g_cursorCount, ecx
    mov g_activeCursorIndex, ecx
    ret
MultiCursor_Init ENDP

MultiCursor_Add PROC line:DWORD, column:DWORD
    LOCAL index:DWORD
    
    mov eax, g_cursorCount
    mov index, eax
    
    .if index >= MAX_CURSORS
        ret
    .endif
    
    ; Add cursor position
    lea rax, g_cursors
    mov rdx, index
    imul rdx, SIZEOF CURSOR
    add rax, rdx
    
    mov [rax].line, line
    mov [rax].column, column
    mov [rax].active, 1
    
    inc g_cursorCount
    
    ret
MultiCursor_Add ENDP

MultiCursor_Remove PROC index:DWORD
    LOCAL i:DWORD
    
    ; Remove cursor at index
    mov i, index
    .while i < g_cursorCount - 1
        ; Shift cursors down
        lea rax, g_cursors
        mov rdx, i
        inc edx
        imul rdx, SIZEOF CURSOR
        add rax, rdx
        mov pSrc, rax
        
        lea rax, g_cursors
        mov rdx, i
        imul rdx, SIZEOF CURSOR
        add rax, rdx
        mov pDst, rax
        
        invoke RtlCopyMemory, pDst, pSrc, SIZEOF CURSOR
        inc i
    .endw
    
    dec g_cursorCount
    
    ret
MultiCursor_Remove ENDP

MultiCursor_InsertText PROC pText:QWORD
    LOCAL i:DWORD
    LOCAL pCursor:QWORD
    
    ; Insert text at all cursor positions
    mov ecx, g_cursorCount
    xor i, i
    .repeat
        lea rax, g_cursors
        mov rdx, i
        imul rdx, SIZECOL CURSOR
        add rax, rdx
        mov pCursor, rax
        
        ; Check if cursor is active
        mov al, [pCursor].active
        .if al != 0
            ; Insert text at cursor position
            invoke Editor_InsertTextAt, [pCursor].line, [pCursor].column, pText
            
            ; Update cursor position
            invoke lstrlenA, pText
            add [pCursor].column, eax
        .endif
        
        inc i
    .untilcxz
    
    ret
MultiCursor_InsertText ENDP

MultiCursor_DeleteSelection PROC startLine:DWORD, startCol:DWORD, endLine:DWORD, endCol:DWORD
    LOCAL i:DWORD
    LOCAL pCursor:QWORD
    
    ; Delete selection at all cursor positions
    mov ecx, g_cursorCount
    xor i, i
    .repeat
        lea rax, g_cursors
        mov rdx, i
        imul rdx, SIZEOF CURSOR
        add rax, rdx
        mov pCursor, rax
        
        ; Check if cursor is in selection range
        mov eax, [pCursor].line
        .if eax >= startLine && eax <= endLine
            ; Delete selection
            invoke Editor_DeleteRange, startLine, startCol, endLine, endCol
        .endif
        
        inc i
    .untilcxz
    
    ret
MultiCursor_DeleteSelection ENDP

MultiCursor_FindAndReplace PROC pFind:QWORD, pReplace:QWORD
    LOCAL i:DWORD
    LOCAL pCursor:QWORD
    LOCAL pText:QWORD
    
    ; Find and replace at all cursor positions
    mov ecx, g_cursorCount
    xor i, i
    .repeat
        lea rax, g_cursors
        mov rdx, i
        imul rdx, SIZEOF CURSOR
        add rax, rdx
        mov pCursor, rax
        
        ; Get text at cursor position
        invoke Editor_GetTextAtCursor, [pCursor].line, [pCursor].column, ADDR pText
        
        ; Check if text matches find pattern
        invoke strstr, pText, pFind
        .if rax != 0
            ; Replace text
            invoke Editor_ReplaceText, [pCursor].line, [pCursor].column, pFind, pReplace
        .endif
        
        inc i
    .untilcxz
    
    ret
MultiCursor_FindAndReplace ENDP

MultiCursor_Render PROC hDC:QWORD
    LOCAL i:DWORD
    LOCAL pCursor:QWORD
    LOCAL rect:RECT
    
    ; Render all cursors
    mov ecx, g_cursorCount
    xor i, i
    .repeat
        lea rax, g_cursors
        mov rdx, i
        imul rdx, SIZEOF CURSOR
        add rax, rdx
        mov pCursor, rax
        
        ; Check if cursor is active
        mov al, [pCursor].active
        .if al != 0
            ; Calculate cursor rectangle
            invoke Editor_GetCursorRect, [pCursor].line, [pCursor].column, ADDR rect
            
            ; Draw cursor
            invoke CreateSolidBrush, RGB(0, 0, 255)
            invoke FillRect, hDC, ADDR rect, rax
            invoke DeleteObject, rax
        .endif
        
        inc i
    .untilcxz
    
    ret
MultiCursor_Render ENDP

END
