;======================================================================
; settings.asm - Registry-Based Settings Persistence
;======================================================================
INCLUDE windows.inc

.CONST
SETTINGS_REGISTRY_KEY DB "Software\RawrXD\AgenticIDE",0
SETTINGS_MAX_VALUE_SIZE EQU 4096

.DATA?
g_hSettingsKey      QWORD ?

.CODE

Settings_Init PROC
    LOCAL dwDisposition:DWORD
    
    ; Create/open registry key
    invoke RegCreateKeyExA, \
        HKEY_CURRENT_USER, \
        ADDR SETTINGS_REGISTRY_KEY, \
        0, \
        0, \
        REG_OPTION_NON_VOLATILE, \
        KEY_ALL_ACCESS, \
        0, \
        ADDR g_hSettingsKey, \
        ADDR dwDisposition
    
    .if eax != ERROR_SUCCESS
        xor rax, rax
        ret
    .endif
    
    mov rax, 1
    ret
Settings_Init ENDP

Settings_GetString PROC pValueName:QWORD, pDefault:QWORD, pBuffer:QWORD, cbBuffer:DWORD
    LOCAL dwType:DWORD
    LOCAL dwSize:DWORD
    
    mov dwSize, cbBuffer
    
    invoke RegQueryValueExA, \
        g_hSettingsKey, \
        pValueName, \
        0, \
        ADDR dwType, \
        pBuffer, \
        ADDR dwSize
    
    .if eax != ERROR_SUCCESS || dwType != REG_SZ
        ; Use default value
        invoke lstrcpyA, pBuffer, pDefault
    .endif
    
    ret
Settings_GetString ENDP

Settings_SetString PROC pValueName:QWORD, pValue:QWORD
    invoke RegSetValueExA, \
        g_hSettingsKey, \
        pValueName, \
        0, \
        REG_SZ, \
        pValue, \
        lstrlenA(pValue)
    
    ret
Settings_SetString ENDP

Settings_GetDword PROC pValueName:QWORD, dwDefault:DWORD
    LOCAL dwValue:DWORD
    LOCAL dwType:DWORD
    LOCAL dwSize:DWORD
    
    mov dwSize, SIZEOF DWORD
    
    invoke RegQueryValueExA, \
        g_hSettingsKey, \
        pValueName, \
        0, \
        ADDR dwType, \
        ADDR dwValue, \
        ADDR dwSize
    
    .if eax != ERROR_SUCCESS || dwType != REG_DWORD
        mov eax, dwDefault
    .else
        mov eax, dwValue
    .endif
    
    ret
Settings_GetDword ENDP

Settings_SetDword PROC pValueName:QWORD, dwValue:DWORD
    invoke RegSetValueExA, \
        g_hSettingsKey, \
        pValueName, \
        0, \
        REG_DWORD, \
        ADDR dwValue, \
        SIZEOF DWORD
    
    ret
Settings_SetDword ENDP

Settings_GetBinary PROC pValueName:QWORD, pBuffer:QWORD, cbBuffer:DWORD
    LOCAL dwType:DWORD
    LOCAL dwSize:DWORD
    
    mov dwSize, cbBuffer
    
    invoke RegQueryValueExA, \
        g_hSettingsKey, \
        pValueName, \
        0, \
        ADDR dwType, \
        pBuffer, \
        ADDR dwSize
    
    .if eax != ERROR_SUCCESS || dwType != REG_BINARY
        xor rax, rax
    .else
        mov rax, dwSize
    .endif
    
    ret
Settings_GetBinary ENDP

Settings_SetBinary PROC pValueName:QWORD, pBuffer:QWORD, cbBuffer:DWORD
    invoke RegSetValueExA, \
        g_hSettingsKey, \
        pValueName, \
        0, \
        REG_BINARY, \
        pBuffer, \
        cbBuffer
    
    ret
Settings_SetBinary ENDP

Settings_DeleteValue PROC pValueName:QWORD
    invoke RegDeleteValueA, g_hSettingsKey, pValueName
    ret
Settings_DeleteValue ENDP

Settings_Export PROC pFilePath:QWORD
    LOCAL hFile:QWORD
    LOCAL pBuffer:QWORD
    LOCAL dwWritten:DWORD
    
    ; Create export file
    invoke CreateFileA, pFilePath, GENERIC_WRITE, 0, 0, CREATE_ALWAYS, 0, 0
    mov hFile, rax
    
    .if hFile == INVALID_HANDLE_VALUE
        xor rax, rax
        ret
    .endif
    
    ; Allocate buffer for settings data
    invoke GetProcessHeap
    mov rcx, rax
    mov rdx, HEAP_ZERO_MEMORY
    mov r8d, SETTINGS_MAX_VALUE_SIZE
    call HeapAlloc
    mov pBuffer, rax
    
    ; Export all settings as JSON
    invoke Settings_ExportAsJson, pBuffer, SETTINGS_MAX_VALUE_SIZE
    
    ; Write to file
    invoke lstrlenA, pBuffer
    invoke WriteFile, hFile, pBuffer, eax, ADDR dwWritten, 0
    
    ; Clean up
    invoke CloseHandle, hFile
    invoke HeapFree, hHeap, 0, pBuffer
    
    mov rax, 1
    ret
Settings_Export ENDP

Settings_Import PROC pFilePath:QWORD
    LOCAL hFile:QWORD
    LOCAL pBuffer:QWORD
    LOCAL fileSize:QWORD
    LOCAL dwRead:DWORD
    
    ; Open import file
    invoke CreateFileA, pFilePath, GENERIC_READ, FILE_SHARE_READ, 0, OPEN_EXISTING, 0, 0
    mov hFile, rax
    
    .if hFile == INVALID_HANDLE_VALUE
        xor rax, rax
        ret
    .endif
    
    ; Get file size
    invoke GetFileSizeEx, hFile, ADDR fileSize
    
    ; Allocate buffer
    invoke GetProcessHeap
    mov rcx, rax
    mov rdx, HEAP_ZERO_MEMORY
    mov r8, fileSize
    call HeapAlloc
    mov pBuffer, rax
    
    ; Read file
    invoke ReadFile, hFile, pBuffer, fileSize, ADDR dwRead, 0
    invoke CloseHandle, hFile
    
    ; Parse and import settings
    invoke Settings_ImportFromJson, pBuffer
    
    ; Clean up
    invoke HeapFree, hHeap, 0, pBuffer
    
    mov rax, 1
    ret
Settings_Import ENDP

Settings_GetDefaultModel PROC
    LOCAL pBuffer[256]:BYTE
    invoke Settings_GetString, "DefaultModel", "gpt-3.5-turbo", ADDR pBuffer, SIZEOF pBuffer
    lea rax, pBuffer
    ret
Settings_GetDefaultModel ENDP

Settings_SetDefaultModel PROC pModel:QWORD
    invoke Settings_SetString, "DefaultModel", pModel
    ret
Settings_SetDefaultModel ENDP

Settings_GetMaxTokens PROC
