    invoke Settings_SetDword, "Temperature", dwTemp
    ret
Settings_SetTemperature ENDP

Settings_Cleanup PROC
    .if g_hSettingsKey != 0
        invoke RegCloseKey, g_hSettingsKey
        xor rax, rax
        mov g_hSettingsKey, rax
    .endif
    ret
Settings_Cleanup ENDP

