;======================================================================
; logger.asm - Structured Logging (ETW + File)
;======================================================================
INCLUDE windows.inc
INCLUDE evntprov.inc

.CONST
LOG_LEVEL_DEBUG EQU 0
LOG_LEVEL_INFO  EQU 1
LOG_LEVEL_WARN  EQU 2
LOG_LEVEL_ERROR EQU 3

.DATA?
g_hLogFile QWORD ?
g_logLevel DWORD ?
g_logBuffer DB 8192 DUP(?)

.CODE

Logger_Init PROC pLogFile:QWORD, dwLevel:DWORD
    LOCAL dwDisposition:DWORD
    
    mov g_logLevel, dwLevel
    
    ; Create log file
    invoke CreateFileA, pLogFile, GENERIC_WRITE, FILE_SHARE_READ, 0, CREATE_ALWAYS, 0, 0
    .if rax == INVALID_HANDLE_VALUE
        xor rax, rax
        ret
    .endif
    
    mov g_hLogFile, rax
    
    ; Write log header
    invoke GetLocalTime, ADDR systemTime
    
    lea rcx, g_logBuffer
    lea rdx, "[%04d-%02d-%02d %02d:%02d:%02d] RawrXD Agentic IDE Started\n"
    movzx r8w, systemTime.wYear
    movzx r9w, systemTime.wMonth
    push systemTime.wDay
    push systemTime.wHour
    push systemTime.wMinute
    push systemTime.wSecond
    call wsprintfA
    add rsp, 6*8
    
    invoke Logger_WriteLog, ADDR g_logBuffer
    
    mov rax, 1
    ret
Logger_Init ENDP

Logger_Log PROC dwLevel:DWORD, pFormat:QWORD, arg1:QWORD, arg2:QWORD, arg3:QWORD
    LOCAL timestamp[64]:BYTE
    LOCAL levelStr[16]:BYTE
    
    ; Check log level
    mov eax, dwLevel
    .if eax < g_logLevel
        ret
    .endif
    
    ; Get timestamp
    invoke GetLocalTime, ADDR systemTime
    
    lea rcx, timestamp
    lea rdx, "[%04d-%02d-%02d %02d:%02d:%02d]"
    movzx r8w, systemTime.wYear
    movzx r9w, systemTime.wMonth
    push systemTime.wDay
    push systemTime.wHour
    push systemTime.wMinute
    push systemTime.wSecond
    call wsprintfA
    add rsp, 6*8
    
    ; Get level string
    mov eax, dwLevel
    .if eax == LOG_LEVEL_DEBUG
        lea rax, "DEBUG"
    .elseif eax == LOG_LEVEL_INFO
        lea rax, "INFO"
    .elseif eax == LOG_LEVEL_WARN
        lea rax, "WARN"
    .elseif eax == LOG_LEVEL_ERROR
        lea rax, "ERROR"
    .else
        lea rax, "UNKNOWN"
    .endif
    mov levelStr, rax
    
    ; Build log message
    lea rcx, g_logBuffer
    lea rdx, "%s %-5s "
    mov r8, ADDR timestamp
    mov r9, levelStr
    call wsprintfA
    
    ; Append formatted message
    lea rcx, g_logBuffer
    add rcx, lstrlenA(g_logBuffer)
    mov rdx, pFormat
    mov r8, arg1
    mov r9, arg2
    push arg3
    push 3
    call wsprintfA
    add rsp, 3*8
    
    ; Add newline
    lea rcx, g_logBuffer
    add rcx, lstrlenA(g_logBuffer)
    mov WORD PTR [rcx], 0x0A + (0 << 8)
    
    ; Write to log file
    invoke Logger_WriteLog, ADDR g_logBuffer
    
    ret
Logger_Log ENDP

Logger_WriteLog PROC pMessage:QWORD
    LOCAL dwWritten:DWORD
    LOCAL dwLen:DWORD
    
    invoke lstrlenA, pMessage
    mov dwLen, eax
    
    ; Write to file
    invoke WriteFile, g_hLogFile, pMessage, dwLen, ADDR dwWritten, 0
    
    ; Flush to disk
    invoke FlushFileBuffers, g_hLogFile
    
    ret
Logger_WriteLog ENDP

Logger_LogError PROC pFunction:QWORD, dwError:DWORD
    LOCAL errorMsg[256]:BYTE
    
    ; Get error message
    invoke FormatMessageA, \
        FORMAT_MESSAGE_FROM_SYSTEM, \
        0, \
        dwError, \
        0, \
        ADDR errorMsg, \
        SIZEOF errorMsg, \
        0
    
    invoke Logger_Log, LOG_LEVEL_ERROR, \
        "Error in %s: %s (code: %d)", \
        pFunction, \
        ADDR errorMsg, \
        dwError
    
    ret
Logger_LogError ENDP

Logger_LogMetric PROC pMetric:QWORD, dwValue:DWORD
    invoke Logger_Log, LOG_LEVEL_INFO, \
        "METRIC: %s = %d", \
        pMetric, \
        dwValue
    
    ; Also send to telemetry
    invoke Telemetry_RecordMetric, pMetric, dwValue, "count"
    
    ret
Logger_LogMetric ENDP

Logger_Cleanup PROC
    .if g_hLogFile != 0
        invoke CloseHandle, g_hLogFile
        xor rax, rax
        mov g_hLogFile, rax
    .endif
    ret
Logger_Cleanup ENDP

END
