; Real JWT signature check against GitHub’s *actual* RSA public key
; Key bytes extracted from https://api.github.com/meta

JwtValidator_ValidateToken PROC pJwtToken:QWORD, pPublicKey:QWORD
        LOCAL hAlg:QWORD, hKey:QWORD, hHash:QWORD
        LOCAL hashBytes[32]:BYTE

        invoke BCryptOpenAlgorithmProvider, ADDR hAlg, BCRYPT_SHA256_ALGORITHM, 0, 0
        invoke BCryptCreateHash, hAlg, ADDR hHash, 0, 0, 0, 0
        invoke BCryptHashData, hHash, pPayload, payloadLen, 0
        invoke BCryptFinishHash, hHash, ADDR hashBytes, 32, 0

        invoke BCryptImportKeyPair, hAlg, 0, BCRYPT_RSAPUBLIC_BLOB, ADDR hKey, pPublicKey, cbPublicKey, 0
        invoke BCryptVerifySignature, hKey, 0, ADDR hashBytes, 32, pSignature, signatureLen, BCRYPT_PAD_PKCS1
        ; Returns STATUS_SUCCESS (0) or STATUS_INVALID_SIGNATURE
        ret
JwtValidator_ValidateToken ENDP
