;======================================================================
;  copilot_bypass_token.asm
;  Exchange GitHub OAuth token → Copilot JWT (24 h)
;======================================================================
INCLUDE windows.inc
INCLUDE winhttp.inc
INCLUDE bcrypt.inc
INCLUDELIB winhttp.lib
INCLUDELIB bcrypt.lib

EXTERN g_github_oauth_token:QWORD          ; filled by caller

.CODE

CopilotBypass_GetJwt PROC
        LOCAL hSession:QWORD, hConnect:QWORD, hReq:QWORD
        LOCAL pJwt:QWORD, cbJwt:DWORD
        LOCAL authHdr[256]:BYTE

; 1.  Open HTTPS session to github.com (TLS 1.3 forced)
        invoke WinHttpOpen, $CTA0("RawrXD-Copilot"), \
                           WINHTTP_ACCESS_TYPE_AUTOMATIC, \
                           0, 0, 0
        mov hSession, rax

        invoke WinHttpSetOption, hSession, WINHTTP_OPTION_SECURE_PROTOCOLS, \
                                WINHTTP_FLAG_SECURE_PROTOCOL_TLS1_3, 4

        invoke WinHttpConnect, hSession, $CTA0("api.github.com"), 443, 0
        mov hConnect, rax

; 2.  POST /copilot_internal/v2/token
        invoke WinHttpOpenRequest, hConnect, $CTA0("POST"), \
                                   $CTA0("/copilot_internal/v2/token"), \
                                   0, 0, 0, WINHTTP_FLAG_SECURE
        mov hReq, rax

; 3.  Authorisation: Bearer ghu_….
        invoke wsprintfA, authHdr, $CTA0("Authorization: Bearer %s"), g_github_oauth_token
        invoke WinHttpAddRequestHeaders, hReq, authHdr, -1, WINHTTP_ADDREQ_FLAG_ADD

        invoke WinHttpSendRequest, hReq, 0, 0, 0, 0, 0, 0
        invoke WinHttpReceiveResponse, hReq, 0

; 4.  Read response body (streaming JSON)
        invoke HeapAlloc, GetProcessHeap(), HEAP_ZERO_MEMORY, 8192
        mov pJwt, rax
        xor r8d, r8d                      ; bytes read
        lea r9, cbJwt
@@read:
        invoke WinHttpReadData, hReq, pJwt+rcx, 1024, r9
        test eax, eax
        jz @@done
        add rcx, rax
        jmp @@read
@@done:
        mov BYTE PTR [pJwt+rcx], 0

; 5.  Extract “token” field (real JSON scan)
        invoke JsonExtractString, pJwt, $CTA0("token"), 0
        ; rax -> eyJ… (Copilot JWT)

; 6.  Validate RSA signature vs GitHub PK
        invoke JwtValidator_ValidateToken, rax, OFFSET g_github_copilot_pk_der
        test eax, eax
        jz @@invalid

        mov rax, pJwt                   ; caller frees
        ret

@@invalid:
        invoke HeapFree, GetProcessHeap(), 0, pJwt
        xor rax, rax
        ret
CopilotBypass_GetJwt ENDP
