void AIChatPanelWiring::initializeWiring() {
    // Core inference connections
    connect(m_panel, &AIChatPanel::messageSubmitted, this, &AIChatPanelWiring::onMessageSubmitted);
    connect(m_engine, &AgenticEngine::responseReady, this, &AIChatPanelWiring::onResponseReady);
    connect(m_engine, &AgenticEngine::tokenGenerated, this, &AIChatPanelWiring::onTokenGenerated);
    connect(m_engine, &AgenticEngine::modelReady, this, &AIChatPanelWiring::onModelReady);
    
