QString ContextInjectionManager::gatherCompleteContext() {
    QStringList contextParts;
    
    // Current file context
    QString currentFile = m_mainWindow->getCurrentFile();
    if (!currentFile.isEmpty()) {
        contextParts << QString("Current file: %1").arg(currentFile);
        
        // File symbols
        QString symbols = getFileSymbols(currentFile);
        if (!symbols.isEmpty()) {
            contextParts << QString("File symbols:\n%1").arg(symbols);
        }
        
        // Language-specific context
        QString langContext = getLanguageSpecificContext(currentFile);
        if (!langContext.isEmpty()) {
            contextParts << langContext;
        }
    }
    
    // Project structure
    QString structure = getProjectStructure();
    if (!structure.isEmpty()) {
        contextParts << QString("Project structure:\n%1").arg(structure);
    }
    
    // Diagnostics
    QString diagnostics = getDiagnostics();
    if (!diagnostics.isEmpty()) {
        contextParts << QString("Current diagnostics:\n%1").arg(diagnostics);
    }
    
    // Recent changes
    QString gitHistory = getRecentGitHistory();
    if (!gitHistory.isEmpty()) {
        contextParts << QString("Recent changes:\n%1").arg(gitHistory);
    }
    
    // Related files
    if (!currentFile.isEmpty()) {
        QString relatedFiles = getRelatedFiles(currentFile);
        if (!relatedFiles.isEmpty()) {
            contextParts << QString("Related files:\n%1").arg(relatedFiles);
        }
    }
    
    return contextParts.join("\n\n");
}

QString ContextInjectionManager::getFileSymbols(const QString& filePath) {
    if (!m_lspClient || !m_lspClient->isReady()) {
        return QString();
    }
    
    DocumentSymbolsParams params;
    params.textDocument.uri = QUrl::fromLocalFile(filePath).toString();
    
    auto symbols = m_lspClient->documentSymbols(params);
    
    QStringList symbolList;
    for (const auto& symbol : symbols) {
        QString symbolStr = QString("- %1 (%2)").arg(symbol.name).arg(symbol.kind);
        if (!symbol.detail.isEmpty()) {
            symbolStr += QString(" - %1").arg(symbol.detail);
        }
        symbolList << symbolStr;
    }
    
    return symbolList.join("\n");
}
