ChatStreamManager_FlushBuffer PROC
    .if streamPos == 0
        ret
    .endif
    
    ; Send EM_SETSEL to move caret to end
    mov rcx, hRichEdit
    mov edx, -1
    mov r8d, -1
    call SendMessageA, rcx, EM_SETSEL, rdx, r8
    
    ; Send EM_REPLACESEL to append text
    lea rdx, streamBuffer
    call SendMessageA, rcx, EM_REPLACESEL, 0, rdx
    
    ; Clear buffer
    mov streamPos, 0
    
    ret
