; tool_integration.asm - Tool Calling Framework
;======================================================================
INCLUDE windows.inc

.CODE

ToolRegistry_Register PROC pToolDef:QWORD
    ; Add tool to global registry
    ; ToolDef structure:
    ; - name (QWORD)
    ; - description (QWORD)
    ; - function pointer (QWORD)
    ; - parameter schema (QWORD)
    
    lea rcx, g_toolRegistry
    mov rdx, pToolDef
    call Vector_Push
    
    ret
ToolRegistry_Register ENDP

ToolExecutor_Call PROC pToolCall:QWORD
    LOCAL toolName:QWORD
    LOCAL pParams:QWORD
    LOCAL resultBuffer[4096]:BYTE
    
    ; Parse tool call JSON
    ; Format: {"name": "tool_name", "parameters": {...}}
    invoke JsonExtractString, pToolCall, "name", ADDR toolNameBuffer
    
    ; Find tool in registry
    lea rcx, g_toolRegistry
    lea rdx, toolNameBuffer
    call ToolRegistry_Find
    
    .if rax == 0
        ; Tool not found
        lea rax, `{"error": "Tool not found"}`,0
        ret
    .endif
    
    mov toolFunc, rax
    
    ; Extract parameters
    invoke JsonExtractObject, pToolCall, "parameters", ADDR paramObject
    
    ; Call tool function
    mov rcx, ADDR paramObject
    call toolFunc
    
    ; Format result as JSON
    lea rcx, resultBuffer
    lea rdx, `{"tool_call_id": "%s", "result": %s}`,0
    mov r8, pToolCallId
    mov r9, rax
    call wsprintfA
    
    lea rax, resultBuffer
    ret
ToolExecutor_Call ENDP

Tool_FileRead PROC pParams:QWORD
    LOCAL filePath:QWORD
    LOCAL pBuffer:QWORD
    LOCAL dwRead:DWORD
    
    ; Extract file path
    invoke JsonExtractString, pParams, "path", ADDR filePathBuffer
    
    ; Open file
    lea rcx, filePathBuffer
    mov edx, GENERIC_READ
    xor r8, r8
    xor r9, r9
    call CreateFileA
    
    .if rax == INVALID_HANDLE_VALUE
        lea rax, `{"error": "File not found"}`,0
        ret
    .endif
    
    mov hFile, rax
    
    ; Get file size
    mov rcx, hFile
    xor rdx, rdx
    call GetFileSizeEx
    
    mov fileSize, rax
    
    ; Allocate buffer
    invoke GetProcessHeap
    mov rcx, rax
    mov rdx, HEAP_ZERO_MEMORY
    mov r8, fileSize
    call HeapAlloc
    
    mov pBuffer, rax
    
    ; Read file
    mov rcx, hFile
    mov rdx, pBuffer
    mov r8d, fileSize
    lea r9, dwRead
    call ReadFile
    
    ; Close file
    mov rcx, hFile
    call CloseHandle
    
    ; Return content as JSON string
    lea rcx, resultBuffer
    lea rdx, `{"content": "%s"}`,0
    mov r8, pBuffer
    call wsprintfA
    
    ; Free buffer
    mov rcx, hHeap
    mov rdx, pBuffer
    call HeapFree
    
    lea rax, resultBuffer
    ret
Tool_FileRead ENDP

Tool_FileWrite PROC pParams:QWORD
    LOCAL filePath:QWORD
