;======================================================================
; symbol_index.asm - Project-Wide Symbol Index (ctags-style)
;======================================================================
INCLUDE windows.inc

.CONST
MAX_SYMBOLS EQU 10000
MAX_FILES EQU 5000

.DATA?
g_symbolTable SYMBOL[MAX_SYMBOLS] DUP(?)  ; {name, file, line, kind}
g_symbolCount DWORD ?
g_fileTable FILE[MAX_FILES] DUP(?)      ; {path, symbols[]}
g_fileCount DWORD ?

.CODE

SymbolIndex_Init PROC
    xor ecx, ecx
    mov g_symbolCount, ecx
    mov g_fileCount, ecx
    ret
SymbolIndex_Init ENDP

SymbolIndex_AddFile PROC pFilePath:QWORD
    LOCAL hFile:QWORD
    LOCAL pBuffer:QWORD
    LOCAL fileSize:QWORD
    LOCAL lineNumber:DWORD
    
    ; Open file
    invoke CreateFileA, pFilePath, GENERIC_READ, FILE_SHARE_READ, 0, OPEN_EXISTING, 0, 0
    mov hFile, rax
    
    .if hFile == INVALID_HANDLE_VALUE
        ret
    .endif
    
    ; Get file size
    invoke GetFileSize, hFile, 0
    mov fileSize, rax
    
    ; Allocate buffer
    invoke GetProcessHeap
    mov rcx, rax
    mov rdx, HEAP_ZERO_MEMORY
    mov r8, fileSize
    call HeapAlloc
    mov pBuffer, rax
    
    ; Read file
    invoke ReadFile, hFile, pBuffer, fileSize, ADDR dwRead, 0
    invoke CloseHandle, hFile
    
    ; Parse symbols
    xor lineNumber, lineNumber
    invoke SymbolIndex_ParseSymbols, pFilePath, pBuffer, fileSize, lineNumber
    
    ; Clean up
    invoke HeapFree, hHeap, 0, pBuffer
    
    ret
SymbolIndex_AddFile ENDP

SymbolIndex_ParseSymbols PROC pFile:QWORD, pContent:QWORD, cbContent:QWORD, startLine:DWORD
    LOCAL pLine:QWORD
    LOCAL lineLen:DWORD
    LOCAL symbolType:DWORD
    LOCAL symbolName[256]:BYTE
    
    ; Language-specific parsing
    invoke SymbolIndex_GetLanguage, pFile
    .if eax == LANG_CPP || eax == LANG_C
        invoke ParseCppSymbols, pContent, cbContent, startLine
    .elseif eax == LANG_PYTHON
        invoke ParsePythonSymbols, pContent, cbContent, startLine
    .elseif eax == LANG_JAVASCRIPT
        invoke ParseJsSymbols, pContent, cbContent, startLine
    .endif
    
    ret
SymbolIndex_ParseSymbols ENDP

SymbolIndex_FindSymbol PROC pSymbolName:QWORD
    LOCAL i:DWORD
    LOCAL pSymbol:QWORD
    
    mov ecx, g_symbolCount
    xor i, i
    .repeat
        lea rax, g_symbolTable
        mov rdx, i
        imul rdx, SIZEOF SYMBOL
        add rax, rdx
        mov pSymbol, rax
        
        ; Compare symbol names
        invoke lstrcmpA, [pSymbol].name, pSymbolName
        .if eax == 0
            mov rax, pSymbol
            ret
        .endif
        
        inc i
    .untilcxz
    
    xor rax, rax
    ret
SymbolIndex_FindSymbol ENDP

SymbolIndex_FindUsages PROC pSymbolName:QWORD
    LOCAL pSymbol:QWORD
    LOCAL pUsages:QWORD
    LOCAL usageCount:DWORD
    
    ; Find symbol definition
    invoke SymbolIndex_FindSymbol, pSymbolName
    mov pSymbol, rax
    
    .if rax == 0
        xor rax, rax
        ret
    .endif
    
    ; Search all files for usages
    invoke GetProcessHeap
    mov rcx, rax
    mov rdx, HEAP_ZERO_MEMORY
    mov r8d, 1000 * SIZEOF USAGE
    call HeapAlloc
    mov pUsages, rax
    
    mov usageCount, 0
    
    ; Search each file
    mov ecx, g_fileCount
    xor i, i
    .repeat
        lea rax, g_fileTable
        mov rdx, i
        imul rdx, SIZEOF FILE
        add rax, rdx
        mov pFile, rax
        
        ; Search for symbol in file
        invoke SearchSymbolInFile, [pFile].path, pSymbolName, pUsages, usageCount
        
        inc i
    .untilcxz
    
    mov rax, pUsages
    ret
SymbolIndex_FindUsages ENDP

ParseCppSymbols PROC pContent:QWORD, cbContent:QWORD, startLine:DWORD
    LOCAL pLine:QWORD
    LOCAL lineNumber:DWORD
    LOCAL pNext:QWORD
    
    mov lineNumber, startLine
    mov pLine, pContent
    
    .repeat
        ; Find end of line
        invoke strchr, pLine, 10
        mov pNext, rax
        
        .if rax == 0
            ; Last line
            mov rax, pContent
            add rax, cbContent
            mov pNext, rax
        .endif
        
        ; Calculate line length
        mov rax, pNext
        sub rax, pLine
        mov lineLen, eax
        
        ; Check for C++ symbols
        invoke CString_Find, pLine, "class "
        .if rax != 0
            ; Extract class name
            invoke ExtractSymbolName, rax + 6, ADDR symbolName
            invoke SymbolIndex_AddSymbol, ADDR symbolName, pFile, lineNumber, SYMBOL_CLASS
        .endif
        
        invoke CString_Find, pLine, "struct "
        .if rax != 0
            invoke ExtractSymbolName, rax + 7, ADDR symbolName
            invoke SymbolIndex_AddSymbol, ADDR symbolName, pFile, lineNumber, SYMBOL_STRUCT
        .endif
        
        invoke CString_Find, pLine, "function "
        .if rax != 0
            invoke ExtractSymbolName, rax + 9, ADDR symbolName
            invoke SymbolIndex_AddSymbol, ADDR symbolName, pFile, lineNumber, SYMBOL_FUNCTION
        .endif
        
        ; Move to next line
        mov pLine, pNext
        inc lineNumber
        
        .if rax >= pContent + cbContent
            .break
        .endif
    .until 0
    
    ret
ParseCppSymbols ENDP

END
