;======================================================================
; diagnostics.asm - LSP Diagnostic Aggregation
;======================================================================
INCLUDE windows.inc

.CONST
MAX_DIAGNOSTICS EQU 1000

.DATA?
g_diagnostics DIAGNOSTIC[MAX_DIAGNOSTICS] DUP(?)
g_diagnosticCount DWORD ?
g_diagnosticSeverity DWORD ?

.CODE

Diagnostics_Init PROC
    xor ecx, ecx
    mov g_diagnosticCount, ecx
    mov g_diagnosticSeverity, 0
    ret
Diagnostics_Init ENDP

Diagnostics_Add PROC pFile:QWORD, pMessage:QWORD, severity:DWORD, line:DWORD, column:DWORD
    LOCAL pDiag:QWORD
    LOCAL index:DWORD
    
    ; Get next available slot
    mov eax, g_diagnosticCount
    mov index, eax
    
    .if index >= MAX_DIAGNOSTICS
        ret
    .endif
    
    ; Fill diagnostic structure
    lea rax, g_diagnostics
    mov rdx, index
    imul rdx, SIZEOF DIAGNOSTIC
    add rax, rdx
    mov pDiag, rax
    
    mov [pDiag].file, pFile
    mov [pDiag].message, pMessage
    mov [pDiag].severity, severity
    mov [pDiag].line, line
    mov [pDiag].column, column
    
    ; Update global severity
    mov eax, severity
    .if eax > g_diagnosticSeverity
        mov g_diagnosticSeverity, eax
    .endif
    
    inc g_diagnosticCount
    
    ret
Diagnostics_Add ENDP

Diagnostics_ClearFile PROC pFile:QWORD
    LOCAL i:DWORD
    LOCAL pDiag:QWORD
    
    ; Remove all diagnostics for this file
    mov ecx, g_diagnosticCount
    xor i, i
    .repeat
        lea rax, g_diagnostics
        mov rdx, i
        imul rdx, SIZEOF DIAGNOSTIC
        add rax, rdx
        mov pDiag, rax
        
        ; Check if this diagnostic is for the file
        invoke lstrcmpA, [pDiag].file, pFile
        .if eax == 0
            ; Shift remaining diagnostics down
            invoke Diagnostics_ShiftDown, i
            dec g_diagnosticCount
            dec i
        .endif
        
        inc i
    .untilcxz
    
    ret
Diagnostics_ClearFile ENDP

Diagnostics_ShiftDown PROC startIndex:DWORD
    LOCAL i:DWORD
    LOCAL pSrc:QWORD
    LOCAL pDst:QWORD
    
    mov i, startIndex
    
    .while i < g_diagnosticCount - 1
        ; Get source and destination pointers
        lea rax, g_diagnostics
        mov rdx, i
        inc edx
        imul rdx, SIZEOF DIAGNOSTIC
        add rax, rdx
        mov pSrc, rax
        
        lea rax, g_diagnostics
        mov rdx, i
        imul rdx, SIZEOF DIAGNOSTIC
        add rax, rdx
        mov pDst, rax
        
        ; Copy diagnostic
        invoke RtlCopyMemory, pDst, pSrc, SIZEOF DIAGNOSTIC
        
        inc i
    .endw
    
    ret
Diagnostics_ShiftDown ENDP

Diagnostics_GetCount PROC
    mov eax, g_diagnosticCount
    ret
Diagnostics_GetCount ENDP

Diagnostics_GetSeverity PROC
    mov eax, g_diagnosticSeverity
    ret
Diagnostics_GetSeverity ENDP

Diagnostics_Render PROC hWnd:QWORD
    LOCAL hDC:QWORD
    LOCAL rect:RECT
    LOCAL i:DWORD
    LOCAL pDiag:QWORD
    
    invoke GetDC, hWnd
    mov hDC, rax
    
    invoke GetClientRect, hWnd, ADDR rect
    
    ; Draw diagnostics list
    mov ecx, g_diagnosticCount
    xor i, i
    .repeat
        lea rax, g_diagnostics
        mov rdx, i
        imul rdx, SIZEOF DIAGNOSTIC
        add rax, rdx
        mov pDiag, rax
        
        ; Calculate position
        mov eax, i
        imul eax, 20          ; 20 pixels per line
        add eax, 10           ; Top margin
        mov rect.top, eax
        
        ; Choose color based on severity
        mov eax, [pDiag].severity
        .if eax == 1          ; Error
            invoke SetTextColor, hDC, RGB(255, 0, 0)
        .elseif eax == 2      ; Warning
