;======================================================================
; git_integration.asm - Git Status/Diff/Commit/Push Integration
;======================================================================
INCLUDE windows.inc

.CONST
GIT_COMMAND_BUFFER_SIZE EQU 4096
MAX_GIT_FILES EQU 1000

.DATA?
g_gitRepoPath QWORD ?
g_gitStatusBuffer DB GIT_COMMAND_BUFFER_SIZE DUP(?)
g_gitDiffBuffer DB GIT_COMMAND_BUFFER_SIZE DUP(?)
g_gitFiles GIT_FILE[MAX_GIT_FILES] DUP(?)
g_gitFileCount DWORD ?

.CODE

GitIntegration_Init PROC pRepoPath:QWORD
    mov g_gitRepoPath, pRepoPath
    call GitIntegration_VerifyRepo
    ret
GitIntegration_Init ENDP

GitIntegration_VerifyRepo PROC
    LOCAL gitCheckCmd[256]:BYTE
    LOCAL hProcess:QWORD
    LOCAL si:STARTUPINFOA
    LOCAL pi:PROCESS_INFORMATION
    
    ; Build git status command to verify repo
    lea rcx, gitCheckCmd
    lea rdx, `git -C "%s" status --porcelain`
    mov r8, g_gitRepoPath
    call wsprintfA
    
    ; Execute command
    invoke ZeroMemory, ADDR si, SIZEOF si
    mov si.cb, SIZEOF si
    mov si.dwFlags, STARTF_USESHOWWINDOW
    mov si.wShowWindow, SW_HIDE
    
    invoke CreateProcessA, 0, ADDR gitCheckCmd, 0, 0, 0, CREATE_NO_WINDOW, 0, 0, ADDR si, ADDR pi
    .if eax == 0
        xor rax, rax          ; Not a git repo
        ret
    .endif
    
    ; Wait for process
    invoke WaitForSingleObject, pi.hProcess, INFINITE
    
    ; Get exit code
    invoke GetExitCodeProcess, pi.hProcess, ADDR exitCode
    .if exitCode != 0
        xor rax, rax
        ret
    .endif
    
    ; Close handles
    invoke CloseHandle, pi.hProcess
    invoke CloseHandle, pi.hThread
    
    mov rax, 1                ; Valid git repo
    ret
GitIntegration_VerifyRepo ENDP

GitIntegration_GetStatus PROC
    LOCAL gitStatusCmd[256]:BYTE
    LOCAL hReadPipe:QWORD
    LOCAL hWritePipe:QWORD
    LOCAL sa:SECURITY_ATTRIBUTES
    LOCAL si:STARTUPINFOA
    LOCAL pi:PROCESS_INFORMATION
    LOCAL dwRead:DWORD
    LOCAL pBuffer:QWORD
    
    ; Create pipe for output
    invoke ZeroMemory, ADDR sa, SIZEOF sa
    mov sa.nLength, SIZEOF sa
    mov sa.bInheritHandle, TRUE
    
    invoke CreatePipe, ADDR hReadPipe, ADDR hWritePipe, ADDR sa, 0
    .if eax == 0
        ret
    .endif
    
    ; Set up startup info
    invoke ZeroMemory, ADDR si, SIZEOF si
    mov si.cb, SIZEOF si
    mov si.dwFlags, STARTF_USESTDHANDLES
    mov si.hStdOutput, hWritePipe
    mov si.hStdError, hWritePipe
    
    ; Build git status command
    lea rcx, gitStatusCmd
    lea rdx, `git -C "%s" status --porcelain`
    mov r8, g_gitRepoPath
    call wsprintfA
    
    ; Execute git status
    invoke CreateProcessA, 0, ADDR gitStatusCmd, 0, 0, TRUE, CREATE_NO_WINDOW, 0, 0, ADDR si, ADDR pi
    .if eax == 0
        invoke CloseHandle, hReadPipe
        invoke CloseHandle, hWritePipe
        ret
    .endif
    
    ; Close write pipe (we only need to read)
    invoke CloseHandle, hWritePipe
    
    ; Allocate buffer for output
    invoke GetProcessHeap
    mov rcx, rax
    mov rdx, HEAP_ZERO_MEMORY
    mov r8d, GIT_COMMAND_BUFFER_SIZE
    call HeapAlloc
    mov pBuffer, rax
    
    ; Read output
    invoke ReadFile, hReadPipe, pBuffer, GIT_COMMAND_BUFFER_SIZE-1, ADDR dwRead, 0
    mov BYTE PTR [pBuffer + dwRead], 0
    
    ; Parse status output
    invoke GitIntegration_ParseStatus, pBuffer
    
    ; Clean up
    invoke CloseHandle, hReadPipe
    invoke CloseHandle, pi.hProcess
    invoke CloseHandle, pi.hThread
    invoke HeapFree, hHeap, 0, pBuffer
    
    ret
GitIntegration_GetStatus ENDP

GitIntegration_ParseStatus PROC pOutput:QWORD
    LOCAL pLine:QWORD
    LOCAL lineLen:DWORD
    LOCAL statusChar:BYTE
    LOCAL fileName[256]:BYTE
    
    xor ecx, ecx
    mov g_gitFileCount, ecx
    
    mov pLine, pOutput
    
    .repeat
        ; Find end of line
        invoke strchr, pLine, 10
        .if rax == 0
            ; Last line
            mov rax, pOutput
            add rax, lstrlenA(pOutput)
            mov pNext, rax
        .else
            mov pNext, rax
            inc pNext
        .endif
        
        ; Calculate line length
        mov rax, pNext
        sub rax, pLine
        mov lineLen, eax
        
        ; Skip empty lines
        .if lineLen == 0
            mov pLine, pNext
            .continue
        .endif
        
        ; Parse status character
        mov al, [pLine]
        mov statusChar, al
        
        ; Extract filename (skip status chars)
        lea rcx, fileName
        add pLine, 3          ; Skip status and space
        invoke strncpy, rcx, pLine, lineLen-3
        mov BYTE PTR [rcx + lineLen-3], 0
        
        ; Add to file list
        invoke GitIntegration_AddFile, ADDR fileName, statusChar
        
        mov pLine, pNext
    .until BYTE PTR [pLine] == 0
    
    ret
GitIntegration_ParseStatus ENDP

GitIntegration_AddFile PROC pFileName:QWORD, status:BYTE
    LOCAL index:DWORD
    
    mov eax, g_gitFileCount
    mov index, eax
    
    .if index >= MAX_GIT_FILES
        ret
    .endif
    
    ; Add file to table
    lea rax, g_gitFiles
    mov rdx, index
    imul rdx, SIZEOF GIT_FILE
    add rax, rdx
    
    mov [rax].path, pFileName
    mov al, status
    mov [rax].status, al
    
    inc g_gitFileCount
    
    ret
GitIntegration_AddFile ENDP

GitIntegration_GetDiff PROC pFilePath:QWORD
    LOCAL gitDiffCmd[512]:BYTE
    LOCAL hReadPipe:QWORD
    LOCAL hWritePipe:QWORD
    LOCAL pBuffer:QWORD
    LOCAL dwRead:DWORD
    
    ; Build git diff command
    lea rcx, gitDiffCmd
    lea rdx, `git -C "%s" diff -- "%s"`
    mov r8, g_gitRepoPath
    mov r9, pFilePath
    call wsprintfA
    
    ; Create pipe and execute command (similar to GetStatus)
    invoke CreatePipe, ADDR hReadPipe, ADDR hWritePipe, 0, 0
    
    ; Set up process with pipe
    invoke ZeroMemory, ADDR si, SIZEOF si
    mov si.cb, SIZEOF si
    mov si.dwFlags, STARTF_USESTDHANDLES
    mov si.hStdOutput, hWritePipe
    
    invoke CreateProcessA, 0, ADDR gitDiffCmd, 0, 0, TRUE, CREATE_NO_WINDOW, 0, 0, ADDR si, ADDR pi
    
    ; Close write pipe
    invoke CloseHandle, hWritePipe
    
    ; Allocate buffer and read diff
    invoke GetProcessHeap
    mov rcx, rax
    mov rdx, HEAP_ZERO_MEMORY
    mov r8d, GIT_COMMAND_BUFFER_SIZE
    call HeapAlloc
    mov pBuffer, rax
    
    invoke ReadFile, hReadPipe, pBuffer, GIT_COMMAND_BUFFER_SIZE-1, ADDR dwRead, 0
    mov BYTE PTR [pBuffer + dwRead], 0
    
    ; Parse diff
    invoke DiffParser_ParseUnifiedDiff, pBuffer
    
    ; Clean up
    invoke CloseHandle, hReadPipe
    invoke CloseHandle, pi.hProcess
    invoke CloseHandle, pi.hThread
    invoke HeapFree, hHeap, 0, pBuffer
    
    ret
GitIntegration_GetDiff ENDP

GitIntegration_Commit PROC pMessage:QWORD
    LOCAL gitCommitCmd[1024]:BYTE
    
    ; Build commit command
    lea rcx, gitCommitCmd
    lea rdx, `git -C "%s" commit -m "%s"`
    mov r8, g_gitRepoPath
    mov r9, pMessage
    call wsprintfA
    
    ; Execute commit
    invoke System_ExecuteCommand, ADDR gitCommitCmd
    
    ret
GitIntegration_Commit ENDP

GitIntegration_Push PROC
    LOCAL gitPushCmd[256]:BYTE
    
    ; Build push command
    lea rcx, gitPushCmd
    lea rdx, `git -C "%s" push`
    mov r8, g_gitRepoPath
    call wsprintfA
    
    ; Execute push
    invoke System_ExecuteCommand, ADDR gitPushCmd
    
    ret
GitIntegration_Push ENDP

END
