CopilotProtocol_Init PROC pJwtToken:QWORD
    mov g_copilotJwtToken, pJwtToken
    
    ; Generate session ID
    invoke BCryptGenRandom, 0, ADDR g_copilotSessionId, 16, BCRYPT_USE_SYSTEM_PREFERRED_RNG
    
    ; Get machine ID (MAC address hash)
    invoke GetMachineId, ADDR g_copilotMachineId
    
    ; Get user ID from JWT
    invoke JwtParser_ExtractUserId, pJwtToken, ADDR g_copilotUserId
    
    ret
CopilotProtocol_Init ENDP

CopilotProtocol_BuildChatRequest PROC pMessages:QWORD, messageCount:DWORD
    LOCAL pRequest:QWORD
    LOCAL pContext:QWORD
    
    ; Build request with Copilot-specific headers
    invoke GetProcessHeap
    mov rcx, rax
    mov rdx, HEAP_ZERO_MEMORY
    mov r8d, 65536
    call HeapAlloc
    mov pRequest, rax
    
    ; Add Copilot metadata
    lea rcx, pRequest
    lea rdx, `{
  "messages": [%s],
  "model": "%s",
  "temperature": 0.2,
  "max_tokens": 2048,
  "top_p": 0.95,
  "n": 1,
  "stream": true,
  "intent": true,
  "nwo": "github/copilot",
  "request_id": "%s",
  "ui_request_id": "%s",
  "metadata": {
    "machineid": "%s",
    "sessionid": "%s",
    "userid": "%s",
    "api_version": "%s",
    "ide": "RawrXD-MASM",
    "ide_version": "1.0.0"
  }
}`,0
    mov r8, pMessages
    mov r9, COPILOT_CHAT_MODEL
    push g_copilotRequestId
    push g_copilotUiRequestId
    push g_copilotMachineId
    push g_copilotSessionId
    push g_copilotUserId
    push COPILOT_API_VERSION
    push 8
    call wsprintfA
    add rsp, 8*8
    
    mov rax, pRequest
    ret
CopilotProtocol_BuildChatRequest ENDP

CopilotProtocol_BuildCompletionRequest PROC pPrefix:QWORD, pSuffix:QWORD
    LOCAL pRequest:QWORD
    LOCAL pContext:QWORD
    
    ; Build completion request with Copilot-specific format
    invoke GetProcessHeap
    mov rcx, rax
    mov rdx, HEAP_ZERO_MEMORY
    mov r8d, 32768
    call HeapAlloc
    mov pRequest, rax
    
    ; Build context with prefix/suffix
    lea rcx, pContext
    lea rdx, `{"prefix": "%s", "suffix": "%s"}`,0
    mov r8, pPrefix
    mov r9, pSuffix
    call wsprintfA
    
    ; Build completion request
    lea rcx, pRequest
    lea rdx, `{
  "prompt": "%s",
  "max_tokens": 100,
  "temperature": 0.1,
  "top_p": 0.95,
  "n": 1,
  "stop": ["\n", "\r", "\t"],
  "language": "c",
  "intent": "continue",
  "suffix": "%s",
  "metadata": {
    "machineid": "%s",
    "sessionid": "%s",
    "userid": "%s"
  }
}`,0
    mov r8, pPrefix
    mov r9, pSuffix
    push g_copilotMachineId
    push g_copilotSessionId
    push g_copilotUserId
    push 3
    call wsprintfA
    add rsp, 3*8
    
    mov rax, pRequest
    ret
CopilotProtocol_BuildCompletionRequest ENDP

CopilotProtocol_ParseInlineCompletion PROC pResponse:QWORD
    LOCAL pCompletion:QWORD
    LOCAL completionText[COMPLETION_MAX_LENGTH]:BYTE
    
    ; Parse inline completion from streaming response
    invoke JsonExtractString, pResponse, "text", ADDR completionText
    
    ; Validate completion
    invoke String_IsValidCode, ADDR completionText
    .if eax == 0
        xor rax, rax
        ret
    .endif
    
    lea rax, completionText
    ret
CopilotProtocol_ParseInlineCompletion ENDP

CopilotProtocol_HandleRateLimit PROC pResponse:QWORD
    LOCAL retryAfter:DWORD
    LOCAL pError:QWORD
    
    ; Check for rate limit headers
    invoke HttpGetHeader, pResponse, "Retry-After", ADDR retryAfter
    
    .if retryAfter > 0
        ; Wait and retry
        invoke Sleep, retryAfter * 1000
        mov rax, 1
    .else
        xor rax, rax
    .endif
    
    ret
CopilotProtocol_HandleRateLimit ENDP

END
