;======================================================================
; windsurf_workspace.asm - Workspace-Wide Context Gathering
;======================================================================
INCLUDE windows.inc

.CONST
MAX_WORKSPACE_FILES EQU 5000
MAX_WORKSPACE_SYMBOLS EQU 10000

.DATA?
g_workspacePath QWORD ?
g_workspaceFiles FILE_INFO[MAX_WORKSPACE_FILES] DUP(?)
g_workspaceFileCount DWORD ?
g_workspaceSymbols SYMBOL_INFO[MAX_WORKSPACE_SYMBOLS] DUP(?)
g_workspaceSymbolCount DWORD ?
g_workspaceDependencies DEPENDENCY[MAX_WORKSPACE_FILES] DUP(?)

.CODE

WindsurfWorkspace_Init PROC pPath:QWORD
    mov g_workspacePath, pPath
    call WindsurfWorkspace_ScanFiles
    call WindsurfWorkspace_BuildDependencyGraph
    ret
WindsurfWorkspace_Init ENDP

WindsurfWorkspace_ScanFiles PROC
    LOCAL searchPath[MAX_PATH]:BYTE
    LOCAL findData:WIN32_FIND_DATAA
    LOCAL hFind:QWORD
    
    ; Build search path: workspace\*
    lea rcx, searchPath
    lea rdx, "%s\\*"
    mov r8, g_workspacePath
    call wsprintfA
    
    ; Find first file
    lea rcx, findData
    mov rdx, searchPath
    call FindFirstFileA
    
    .if rax == INVALID_HANDLE_VALUE
        ret
    .endif
    
    mov hFind, rax
    
    ; Process each file
    .repeat
        ; Skip . and ..
        lea rax, findData.cFileName
        invoke lstrcmpA, rax, "."
        .if eax == 0
            .continue
        .endif
        
        invoke lstrcmpA, rax, ".."
        .if eax == 0
            .continue
        .endif
        
        ; Check if directory
        test findData.dwFileAttributes, FILE_ATTRIBUTE_DIRECTORY
        .if !ZERO?
            ; Recurse into subdirectory
            lea rcx, searchPath
            lea rdx, "%s\\%s"
            mov r8, g_workspacePath
            lea r9, findData.cFileName
            call wsprintfA
            
            invoke WindsurfWorkspace_ScanDirectory, searchPath
        .else
            ; Process file
            invoke WindsurfWorkspace_ProcessFile, g_workspacePath, ADDR findData.cFileName
        .endif
        
        ; Find next file
        lea rcx, findData
        mov rdx, hFind
        call FindNextFileA
        
    .until rax == 0
    
    ; Close find handle
    mov rcx, hFind
    call FindClose
    
    ret
WindsurfWorkspace_ScanFiles ENDP

WindsurfWorkspace_ProcessFile PROC pDir:QWORD, pFileName:QWORD
    LOCAL pFullPath:QWORD
    LOCAL fileExt:QWORD
    LOCAL fileSize:QWORD
    LOCAL fileHash:QWORD
    
    ; Build full path
    invoke GetProcessHeap
    mov rcx, rax
    mov rdx, HEAP_ZERO_MEMORY
    mov r8d, MAX_PATH
    call HeapAlloc
    mov pFullPath, rax
    
    lea rcx, pFullPath
    lea rdx, "%s\\%s"
    mov r8, pDir
    mov r9, pFileName
    call wsprintfA
    
    ; Get file extension
    invoke strrchr, pFileName, '.'
    .if rax != 0
        inc rax
        mov fileExt, rax
    .else
        mov fileExt, 0
    .endif
    
    ; Get file size
    invoke GetFileSizeEx, pFullPath, ADDR fileSize
    
    ; Calculate file hash
    invoke HashFile_MD5, pFullPath, ADDR fileHash
    
    ; Add to workspace index
    invoke WindsurfWorkspace_AddFile, pFullPath, fileExt, fileSize, fileHash
    
    ; Extract symbols if code file
    invoke WindsurfWorkspace_IsCodeFile, fileExt
    .if eax != 0
        invoke WindsurfWorkspace_ExtractSymbols, pFullPath
    .endif
    
    ; Clean up
    invoke HeapFree, hHeap, 0, pFullPath
    
    ret
WindsurfWorkspace_ProcessFile ENDP

WindsurfWorkspace_ExtractSymbols PROC pFilePath:QWORD
    LOCAL pContent:QWORD
    LOCAL contentSize:QWORD
    LOCAL language:DWORD
    
    ; Read file content
    invoke FileRead_All, pFilePath, ADDR pContent, ADDR contentSize
    .if rax == 0
        ret
    .endif
    
    ; Detect language
    invoke LanguageDetector_Detect, pFilePath
    mov language, eax
    
    ; Extract symbols based on language
    .if language == LANG_PYTHON
        invoke PythonParser_ExtractSymbols, pContent, contentSize, pFilePath
    .elseif language == LANG_JAVASCRIPT
        invoke JsParser_ExtractSymbols, pContent, contentSize, pFilePath
    .elseif language == LANG_CPP || language == LANG_C
        invoke CppParser_ExtractSymbols, pContent, contentSize, pFilePath
    .endif
    
    ; Clean up
    invoke HeapFree, hHeap, 0, pContent
    
    ret
WindsurfWorkspace_ExtractSymbols ENDP

WindsurfWorkspace_GetContext PROC pCurrentFile:QWORD
    LOCAL pContext:QWORD
    LOCAL pRelatedFiles:QWORD
    LOCAL pImports:QWORD
    LOCAL pSymbols:QWORD
    
    ; Allocate context buffer
    invoke GetProcessHeap
    mov rcx, rax
    mov rdx, HEAP_ZERO_MEMORY
    mov r8d, 65536
    call HeapAlloc
    mov pContext, rax
    
    ; Find related files
    invoke WindsurfWorkspace_FindRelatedFiles, pCurrentFile
    mov pRelatedFiles, rax
    
    ; Find imports/dependencies
    invoke WindsurfWorkspace_FindImports, pCurrentFile
    mov pImports, rax
    
    ; Find relevant symbols
    invoke WindsurfWorkspace_FindRelevantSymbols, pCurrentFile
    mov pSymbols, rax
    
    ; Build context string
    lea rcx, pContext
    lea rdx, `Workspace Context:\n\nCurrent file: %s\n\nRelated files:\n%s\n\nImports:\n%s\n\nRelevant symbols:\n%s\n\nProject structure:\n%s`
    mov r8, pCurrentFile
    mov r9, pRelatedFiles
    push pSymbols
    push pImports
    push pRelatedFiles
    push pCurrentFile
    call wsprintfA
    add rsp, 5*8
    
    mov rax, pContext
    ret
WindsurfWorkspace_GetContext ENDP

WindsurfWorkspace_FindRelatedFiles PROC pFile:QWORD
    LOCAL pResults:QWORD
    LOCAL resultCount:DWORD
    
    ; Allocate results buffer
    invoke GetProcessHeap
    mov rcx, rax
    mov rdx, HEAP_ZERO_MEMORY
    mov r8d, 4096
    call HeapAlloc
    mov pResults, rax
    
    ; Find files that import this file
    invoke DependencyFinder_FindImporters, pFile, pResults, ADDR resultCount
    
    ; Find files in same directory
    invoke DirectoryFinder_FindSiblings, pFile, pResults, ADDR resultCount
    
    ; Find files with similar names
    invoke SimilarityFinder_FindSimilar, pFile, pResults, ADDR resultCount
    
    mov rax, pResults
    ret
WindsurfWorkspace_FindRelatedFiles ENDP

