;======================================================================
; amazon_sagemaker.asm - SageMaker Real-Time Endpoint Client
;======================================================================
INCLUDE windows.inc

.CONST
SAGEMAKER_REGION      DB "us-east-1",0
SAGEMAKER_SERVICE     DB "sagemaker",0
SAGEMAKER_HOST        DB "runtime.sagemaker.us-east-1.amazonaws.com",0
SAGEMAKER_URI         DB "/endpoints/",0

.DATA?
g_sagemakerEndpoint   DB 256 DUP(?)
g_sagemakerAccessKey  DB 128 DUP(?)
g_sagemakerSecretKey  DB 128 DUP(?)
g_sagemakerSessionToken DB 256 DUP(?)

.CODE

SageMaker_Init PROC pEndpoint:QWORD, pAccessKey:QWORD, pSecretKey:QWORD, pSessionToken:QWORD
    invoke lstrcpyA, ADDR g_sagemakerEndpoint, pEndpoint
    invoke lstrcpyA, ADDR g_sagemakerAccessKey, pAccessKey
    invoke lstrcpyA, ADDR g_sagemakerSecretKey, pSecretKey
    .if pSessionToken != 0
        invoke lstrcpyA, ADDR g_sagemakerSessionToken, pSessionToken
    .endif
    ret
SageMaker_Init ENDP

SageMaker_InvokeEndpoint PROC pPayload:QWORD, cbPayload:DWORD
    LOCAL pRequest:QWORD
    LOCAL pHeaders:QWORD
    LOCAL pSignature:QWORD
    LOCAL timestamp[64]:BYTE
    LOCAL dateStamp[32]:BYTE
    
    ; Get current timestamp
    invoke GetSystemTimeAsFileTime, ADDR fileTime
    invoke FileTimeToSystemTime, ADDR fileTime, ADDR systemTime
    
    ; Format timestamp (ISO8601)
    lea rcx, timestamp
    lea rdx, "%04d%02d%02dT%02d%02d%02dZ"
    movzx r8w, systemTime.wYear
    movzx r9w, systemTime.wMonth
    push systemTime.wDay
    push systemTime.wHour
    push systemTime.wMinute
    push systemTime.wSecond
    call wsprintfA
    add rsp, 5*8
    
    ; Format date stamp
    lea rcx, dateStamp
    lea rdx, "%04d%02d%02d"
    movzx r8w, systemTime.wYear
    movzx r9w, systemTime.wMonth
    push systemTime.wDay
    call wsprintfA
    add rsp, 3*8
    
    ; Build AWS Signature Version 4
    invoke AwsSigV4_SignRequest, \
        "POST", \
        SAGEMAKER_URI, \
        g_sagemakerEndpoint, \
        pPayload, \
        cbPayload, \
        ADDR timestamp, \
        ADDR dateStamp, \
        SAGEMAKER_SERVICE, \
        SAGEMAKER_REGION, \
        g_sagemakerAccessKey, \
        g_sagemakerSecretKey
    
    mov pSignature, rax
    
    ; Build request headers
    invoke GetProcessHeap
    mov rcx, rax
    mov rdx, HEAP_ZERO_MEMORY
    mov r8d, 4096
    call HeapAlloc
    mov pHeaders, rax
    
    lea rcx, pHeaders
    lea rdx, `Host: %s\r\nX-Amz-Date: %s\r\nX-Amz-Security-Token: %s\r\nAuthorization: AWS4-HMAC-SHA256 Credential=%s/%s/%s/%s/aws4_request, SignedHeaders=host;x-amz-date, Signature=%s\r\nContent-Type: application/json\r\nContent-Length: %d\r\n`
    mov r8, SAGEMAKER_HOST
    mov r9, ADDR timestamp
    push cbPayload
    push pSignature
    push SAGEMAKER_REGION
    push SAGEMAKER_SERVICE
    push ADDR dateStamp
    push g_sagemakerAccessKey
    push g_sagemakerSessionToken
    push 8
    call wsprintfA
    add rsp, 8*8
    
    ; Send request to SageMaker
    invoke HttpsPost, SAGEMAKER_HOST, SAGEMAKER_URI, pHeaders, pPayload, cbPayload
    
    ; Clean up
    invoke HeapFree, hHeap, 0, pHeaders
    invoke HeapFree, hHeap, 0, pSignature
    
    ret
SageMaker_InvokeEndpoint ENDP

SageMaker_ParseResponse PROC pResponse:QWORD
    LOCAL pResult:QWORD
    LOCAL jsonBuffer[8192]:BYTE
    
    ; Parse JSON response
    invoke JsonParseObject, pResponse
    mov pResult, rax
    
    ; Extract predictions
    invoke JsonExtractArray, pResult, "predictions"
    .if rax != 0
        ; Process predictions
        invoke SageMaker_ProcessPredictions, rax
    .endif
    
    ret
SageMaker_ParseResponse ENDP

SageMaker_ProcessPredictions PROC pPredictions:QWORD
    LOCAL predictionCount:DWORD
    LOCAL i:DWORD
    LOCAL pPrediction:QWORD
    
    ; Get prediction count
    invoke JsonArray_GetLength, pPredictions
    mov predictionCount, eax
    
    ; Process each prediction
    xor i, i
    .repeat
        invoke JsonArray_GetElement, pPredictions, i
        mov pPrediction, rax
        
        ; Extract prediction data
        invoke JsonExtractString, pPrediction, "generated_text", ADDR generatedText
        
        ; Add to model output
        invoke ModelOutput_AddPrediction, ADDR generatedText
        
        inc i
    .until i >= predictionCount
    
    ret
SageMaker_ProcessPredictions ENDP

END
