;======================================================================
; telemetry.asm - Structured Telemetry (No PII)
;======================================================================
INCLUDE windows.inc

.CONST
TELEMETRY_ENDPOINT DB "https://telemetry.rawrxd.com/api/events",0
TELEMETRY_BATCH_SIZE EQU 100

.DATA?
g_telemetryEvents TELEMETRY_EVENT[TELEMETRY_BATCH_SIZE] DUP(?)
g_telemetryEventCount DWORD ?
g_telemetrySessionId QWORD ?
g_telemetryMachineId QWORD ?
g_telemetryUserId QWORD ?

.CODE

Telemetry_Init PROC pSessionId:QWORD, pMachineId:QWORD, pUserId:QWORD
    mov g_telemetrySessionId, pSessionId
    mov g_telemetryMachineId, pMachineId
    mov g_telemetryUserId, pUserId
    xor ecx, ecx
    mov g_telemetryEventCount, ecx
    ret
Telemetry_Init ENDP

Telemetry_RecordEvent PROC pEventName:QWORD, pProperties:QWORD
    LOCAL pEvent:QWORD
    LOCAL index:DWORD
    LOCAL timestamp[64]:BYTE
    
    ; Get current timestamp
    invoke GetSystemTimeAsFileTime, ADDR fileTime
    invoke FileTimeToSystemTime, ADDR fileTime, ADDR systemTime
    
    ; Format ISO timestamp
    lea rcx, timestamp
    lea rdx, "%04d-%02d-%02dT%02d:%02d:%02d.%03dZ"
    movzx r8w, systemTime.wYear
    movzx r9w, systemTime.wMonth
    push systemTime.wMilliseconds
    push systemTime.wSecond
    push systemTime.wMinute
    push systemTime.wHour
    push systemTime.wDay
    call wsprintfA
    add rsp, 6*8
    
    ; Get next event slot
    mov eax, g_telemetryEventCount
    mov index, eax
    
    .if index >= TELEMETRY_BATCH_SIZE
        ; Flush batch
        invoke Telemetry_FlushBatch
        mov index, 0
    .endif
    
    ; Fill event structure
    lea rax, g_telemetryEvents
    mov rdx, index
    imul rdx, SIZEOF TELEMETRY_EVENT
    add rax, rdx
    mov pEvent, rax
    
    mov [pEvent].name, pEventName
    mov [pEvent].timestamp, ADDR timestamp
    mov [pEvent].properties, pProperties
    mov [pEvent].sessionId, g_telemetrySessionId
    mov [pEvent].machineId, g_telemetryMachineId
    
    inc g_telemetryEventCount
    
    ret
Telemetry_RecordEvent ENDP

Telemetry_RecordMetric PROC pMetricName:QWORD, value:QWORD, pUnit:QWORD
    LOCAL pMetric:QWORD
    LOCAL metricJson[256]:BYTE
    
    ; Build metric JSON
    lea rcx, metricJson
    lea rdx, `{"name": "%s", "value": %lld, "unit": "%s"}`
    mov r8, pMetricName
    mov r9, value
    push pUnit
    push 1
    call wsprintfA
    add rsp, 2*8
    
    ; Record as telemetry event
    invoke Telemetry_RecordEvent, "metric", ADDR metricJson
    
    ret
Telemetry_RecordMetric ENDP

Telemetry_RecordError PROC pErrorType:QWORD, pErrorMessage:QWORD, pStackTrace:QWORD
    LOCAL pError:QWORD
    LOCAL errorJson[1024]:BYTE
    
    ; Build error JSON (no PII)
    lea rcx, errorJson
    lea rdx, `{"type": "%s", "message": "%s", "stack": "%s"}`
    mov r8, pErrorType
    mov r9, pErrorMessage
    push pStackTrace
    push 3
    call wsprintfA
    add rsp, 3*8
    
    ; Record as telemetry event
    invoke Telemetry_RecordEvent, "error", ADDR errorJson
    
    ret
Telemetry_RecordError ENDP

Telemetry_FlushBatch PROC
    LOCAL pBatchJson:QWORD
    LOCAL pRequestBody:QWORD
    
    .if g_telemetryEventCount == 0
        ret
    .endif
    
    ; Build batch JSON
    invoke GetProcessHeap
    mov rcx, rax
    mov rdx, HEAP_ZERO_MEMORY
    mov r8d, 65536
    call HeapAlloc
    mov pBatchJson, rax
    
    ; Start JSON array
    lea rcx, pBatchJson
    lea rdx, `[`
    call lstrcpyA
    
    ; Add all events
    mov ecx, g_telemetryEventCount
    xor i, i
    .repeat
        lea rax, g_telemetryEvents
        mov rdx, i
        imul rdx, SIZEOF TELEMETRY_EVENT
        add rax, rdx
        
        ; Append event to JSON array
        lea rcx, pBatchJson
        add rcx, lstrlenA(pBatchJson)
        lea rdx, `{"name": "%s", "timestamp": "%s", "session_id": "%s", "machine_id": "%s", "properties": %s}`
        mov r8, [rax].name
        mov r9, [rax].timestamp
        push [rax].machineId
        push [rax].sessionId
        push [rax].properties
        push 5
        call wsprintfA
        add rsp, 5*8
        
        ; Add comma if not last
        .if i < g_telemetryEventCount - 1
            lea rcx, pBatchJson
            add rcx, lstrlenA(pBatchJson)
            mov BYTE PTR [rcx], ','
            mov BYTE PTR [rcx+1], 0
        .endif
        
        inc i
    .untilcxz
    
    ; Close JSON array
    lea rcx, pBatchJson
    add rcx, lstrlenA(pBatchJson)
    mov WORD PTR [rcx], ']' + (0 << 8)
    
    ; Send to telemetry endpoint
    invoke HttpPostJson, TELEMETRY_ENDPOINT, pBatchJson, lstrlenA(pBatchJson)
    
    ; Reset batch
    xor ecx, ecx
    mov g_telemetryEventCount, ecx
    
    ; Clean up
    invoke HeapFree, hHeap, 0, pBatchJson
    
    ret
Telemetry_FlushBatch ENDP

Telemetry_Shutdown PROC
    ; Flush remaining events
    invoke Telemetry_FlushBatch
    ret
Telemetry_Shutdown ENDP

END
