Settings_Export PROC pFilePath:QWORD
    LOCAL hFile:QWORD
    LOCAL pBuffer:QWORD
    LOCAL dwWritten:DWORD
    
    ; Create export file
    invoke CreateFileA, pFilePath, GENERIC_WRITE, 0, 0, CREATE_ALWAYS, 0, 0
    mov hFile, rax
    
    .if hFile == INVALID_HANDLE_VALUE
        xor rax, rax
        ret
    .endif
    
    ; Allocate buffer for settings data
    invoke GetProcessHeap
    mov rcx, rax
    mov rdx, HEAP_ZERO_MEMORY
    mov r8d, SETTINGS_MAX_VALUE_SIZE
    call HeapAlloc
    mov pBuffer, rax
    
    ; Export all settings as JSON
    invoke Settings_ExportAsJson, pBuffer, SETTINGS_MAX_VALUE_SIZE
    
    ; Write to file
    invoke lstrlenA, pBuffer
    invoke WriteFile, hFile, pBuffer, eax, ADDR dwWritten, 0
    
    ; Clean up
    invoke CloseHandle, hFile
    invoke HeapFree, hHeap, 0, pBuffer
    
    mov rax, 1
    ret
Settings_Export ENDP

Settings_Import PROC pFilePath:QWORD
    LOCAL hFile:QWORD
    LOCAL pBuffer:QWORD
    LOCAL fileSize:QWORD
    LOCAL dwRead:DWORD
    
    ; Open import file
    invoke CreateFileA, pFilePath, GENERIC_READ, FILE_SHARE_READ, 0, OPEN_EXISTING, 0, 0
    mov hFile, rax
    
    .if hFile == INVALID_HANDLE_VALUE
        xor rax, rax
        ret
    .endif
    
    ; Get file size
    invoke GetFileSizeEx, hFile, ADDR fileSize
    
    ; Allocate buffer
    invoke GetProcessHeap
