;======================================================================
; security.asm - JWT Validation & Sandbox Policy
;======================================================================
INCLUDE windows.inc
INCLUDE bcrypt.inc

.CONST
JWT_MAX_CLAIMS EQU 50
SANDBOX_POLICY_MAX_RULES EQU 100

.DATA?
g_jwtClaims JWT_CLAIM[JWT_MAX_CLAIMS] DUP(?)
g_jwtClaimCount DWORD ?
g_sandboxPolicy SANDBOX_RULE[SANDBOX_POLICY_MAX_RULES] DUP(?)
g_sandboxRuleCount DWORD ?
g_isSandboxEnabled DWORD ?

.CODE

Security_Init PROC
    xor ecx, ecx
    mov g_jwtClaimCount, ecx
    mov g_sandboxRuleCount, ecx
    mov g_isSandboxEnabled, 1
    ret
Security_Init ENDP

JwtValidator_ValidateToken PROC pJwtToken:QWORD, pPublicKey:QWORD
    LOCAL pHeader:QWORD
    LOCAL pPayload:QWORD
    LOCAL pSignature:QWORD
    LOCAL headerLen:DWORD
    LOCAL payloadLen:DWORD
    LOCAL signatureLen:DWORD
    
    ; Split JWT into parts
    invoke JwtParser_SplitToken, pJwtToken, ADDR pHeader, ADDR pPayload, ADDR pSignature
    mov headerLen, eax
    mov payloadLen, edx
    mov signatureLen, ecx
    
    ; Validate signature
    invoke RsaVerifySignature, pPayload, payloadLen, pSignature, signatureLen, pPublicKey
    
    .if eax == 0
        xor rax, rax          ; Invalid signature
        ret
    .endif
    
    ; Parse claims
    invoke JwtParser_ParseClaims, pPayload, payloadLen
    
    ; Validate required claims
    invoke JwtValidator_ValidateRequiredClaims
    
    mov rax, 1                ; Valid token
    ret
JwtValidator_ValidateToken ENDP

JwtValidator_ValidateRequiredClaims PROC
    LOCAL pExp:QWORD
    LOCAL pIat:QWORD
    LOCAL pAud:QWORD
    LOCAL expTime:QWORD
    LOCAL currentTime:QWORD
    
    ; Check expiration (exp claim)
    invoke JwtParser_GetClaim, "exp"
    mov pExp, rax
    
    .if pExp == 0
        xor rax, rax          ; Missing exp claim
        ret
    .endif
    
    invoke strtoull, pExp, 0, 10
    mov expTime, rax
    
    invoke time, 0
    mov currentTime, rax
    
    .if currentTime > expTime
        xor rax, rax          ; Token expired
        ret
    .endif
    
    ; Check issued at (iat claim)
    invoke JwtParser_GetClaim, "iat"
    mov pIat, rax
    
    .if pIat != 0
        invoke strtoull, pIat, 0, 10
        .if rax > currentTime
            xor rax, rax      ; Token issued in future
            ret
        .endif
    .endif
    
    ; Check audience (aud claim)
    invoke JwtParser_GetClaim, "aud"
    mov pAud, rax
    
    .if pAud != 0
        invoke lstrcmpA, pAud, ADDR expectedAudience
        .if eax != 0
            xor rax, rax      ; Invalid audience
            ret
        .endif
    .endif
    
    mov rax, 1                ; All claims valid
    ret
JwtValidator_ValidateRequiredClaims ENDP

SandboxPolicy_AddRule PROC pRule:QWORD
    LOCAL index:DWORD
    
    mov eax, g_sandboxRuleCount
    mov index, eax
    
    .if index >= SANDBOX_POLICY_MAX_RULES
        ret
    .endif
    
    ; Add rule to policy
    lea rax, g_sandboxPolicy
    mov rdx, index
    imul rdx, SIZEOF SANDBOX_RULE
    add rax, rdx
    
    invoke RtlCopyMemory, rax, pRule, SIZEOF SANDBOX_RULE
    
    inc g_sandboxRuleCount
    
    ret
SandboxPolicy_AddRule ENDP

SandboxPolicy_CheckAccess PROC pAction:QWORD, pResource:QWORD
    LOCAL i:DWORD
    LOCAL pRule:QWORD
    
    ; Check each rule
    mov ecx, g_sandboxRuleCount
    xor i, i
    .repeat
        lea rax, g_sandboxPolicy
        mov rdx, i
        imul rdx, SIZEOF SANDBOX_RULE
        add rax, rdx
        mov pRule, rax
        
        ; Check if rule matches action and resource
        invoke lstrcmpA, [pRule].action, pAction
        .if eax == 0
            invoke lstrcmpA, [pRule].resource, pResource
            .if eax == 0
                ; Rule matches - return permission
                mov eax, [pRule].permission
                ret
            .endif
        .endif
        
        inc i
    .untilcxz
    
    ; No matching rule - deny by default
    mov eax, SANDBOX_DENY
    ret
SandboxPolicy_CheckAccess ENDP

SandboxPolicy_Enforce PROC pAction:QWORD, pResource:QWORD
    LOCAL permission:DWORD
    
    .if g_isSandboxEnabled == 0
        mov rax, 1                ; Sandbox disabled - allow all
        ret
    .endif
    
    ; Check access permission
    invoke SandboxPolicy_CheckAccess, pAction, pResource
    mov permission, eax
    
    .if permission == SANDBOX_DENY
        ; Log security violation
        invoke Telemetry_RecordEvent, "security_violation", pAction
        
        xor rax, rax              ; Access denied
        ret
    .endif
    
    mov rax, 1                    ; Access allowed
    ret
SandboxPolicy_Enforce ENDP

Security_SandboxFileAccess PROC pFilePath:QWORD, accessMode:DWORD
    LOCAL pAction:QWORD
    
    ; Determine action based on access mode
    .if accessMode == GENERIC_READ
        lea pAction, "file_read"
    .elseif accessMode == GENERIC_WRITE
        lea pAction, "file_write"
    .elseif accessMode == GENERIC_EXECUTE
        lea pAction, "file_execute"
    .else
        lea pAction, "file_access"
